    <span
      role="group"
      aria-label={ariaLabel}
      className={cn('inline-flex items-center gap-1 text-sm flex-wrap', className)}
    >
      <span className="font-semibold" style={{ color: 'var(--text-price)' }}>
        {formattedPrice}
