import { cn } from "@/lib/utils"

export type PriceTagVariant = 'inline' | 'detailed' | 'compact'
type TrendDirection = 'up' | 'down' | 'stable'

interface PriceTagProps {
  /** Dollar amount (e.g. `12.99`), **not** smallest currency unit (cents). `null` renders "No sellers". */
  price: number | null
  sellerCount?: number
  marketAvg?: number
  trend?: TrendDirection
  variant: PriceTagVariant
  className?: string
}

/**
 * Renders a formatted USD price with optional seller count, market average, and trend indicator.
 *
 * Uses tabular figures (`font-feature-settings: 'tnum'`) so prices align cleanly in columns.
 *
 * @remarks
 * The `price` prop expects a **dollar value** (e.g. `12.99`), not the smallest currency unit (cents).
 * Passing `1299` would render as `$1,299.00`, not `$12.99`.
 */
export function PriceTag({
  price,
  sellerCount,
  marketAvg,
  trend,
  variant,
  className,
}: PriceTagProps) {
  if (price === null || price === undefined) {
    return <NoSellers className={className} />
  }

  const formattedPrice = formatPrice(price)
  const formattedMarketAvg = marketAvg != null ? formatPrice(marketAvg) : null

  const ariaLabel = [
    formattedPrice,
    sellerCount != null ? sellerLabel(sellerCount) : null,
  ]
    .filter(Boolean)
    .join(', ')

  if (variant === 'compact') {
    return (
      <span
        role="group"
        aria-label={ariaLabel || formattedPrice}
        className={cn('price text-sm font-semibold', className)}
      >
        {formattedPrice}
      </span>
    )
  }

  if (variant === 'inline') {
    return (
      <span
        role="group"
        aria-label={ariaLabel}
        className={cn('inline-flex items-center gap-1 text-sm', className)}
      >
        <span className="price font-semibold">
          {formattedPrice}
        </span>
        {sellerCount != null && sellerCount > 0 && (
          <span style={{ color: 'var(--muted-foreground)' }}>
            · {sellerLabel(sellerCount)}
          </span>
        )}
        {trend && trend !== 'stable' && <TrendIcon direction={trend} />}
      </span>
    )
  }

  // detailed
  return (
    <span
      role="group"
      aria-label={ariaLabel}
      className={cn('inline-flex items-center gap-1 text-sm flex-wrap', className)}
    >
      <span className="price font-semibold">
        {formattedPrice}
      </span>
      {sellerCount != null && sellerCount > 0 && (
        <span style={{ color: 'var(--muted-foreground)' }}>
          · from {sellerLabel(sellerCount)}
        </span>
      )}
      {formattedMarketAvg && (
        <span style={{ color: 'var(--muted-foreground)' }}>
          · market avg {formattedMarketAvg}
        </span>
      )}
      {trend && trend !== 'stable' && <TrendIcon direction={trend} />}
    </span>
  )
}

// ---------------------------------------------------------------------------
// Internal helpers
// ---------------------------------------------------------------------------

function formatPrice(price: number): string {
  return new Intl.NumberFormat('en-US', {
    style: 'currency',
    currency: 'USD',
    minimumFractionDigits: 2,
  }).format(price)
}

function sellerLabel(count: number): string {
  return count === 1 ? '1 seller' : `${count} sellers`
}

function TrendIcon({ direction }: { direction: TrendDirection }) {
  if (direction === 'stable') return null
  const isDown = direction === 'down'
  return (
    <span
      aria-label={`trending ${direction}`}
      role="img"
      style={{ color: isDown ? 'var(--positive)' : 'var(--warning)' }}
    >
      {isDown ? '↓' : '↑'}
    </span>
  )
}

function NoSellers({ className }: { className?: string }) {
  return (
    <span
      role="group"
      aria-label="No sellers available"
      className={cn('text-sm', className)}
      style={{ color: 'var(--muted-foreground)' }}
    >
      No sellers
    </span>
  )
}

